-- =====================================================
-- 075: 주유소 Google Places 구역 보강 시드 (searchNearby, 29개 활성 구역)
--   074(OSM) 이후 추가. 각 구역 center 반경 3km gas_station 검색,
--   기존(GOOGLE58+OSM339)과 50m 중복 제외한 141건. source_type=GOOGLE,
--   external_id=Places place_id. 멱등(partial unique index + ON CONFLICT).
-- =====================================================

CREATE UNIQUE INDEX IF NOT EXISTS gas_station_external_id_uidx ON gas_station(external_id) WHERE external_id IS NOT NULL;


ON CONFLICT (external_id) WHERE external_id IS NOT NULL DO NOTHING;
